use crate::error::Result;
use crate::{CheckResult, CompileTimeCheck};
use alien_core::{Platform, Stack};
use std::collections::HashSet;

/// Ensures the stack contains only allowed user-defined resources.
///
/// Some resources like `AzureResourceGroup` and `RemoteStackManagement`
/// are system-managed and should not be manually added.
///
/// Note: While most ServiceAccounts are auto-generated by mutations (one per permission profile),
/// users CAN manually define ServiceAccounts for special cases like cross-account impersonation.
pub struct AllowedUserResourcesCheck;

#[async_trait::async_trait]
impl CompileTimeCheck for AllowedUserResourcesCheck {
    fn description(&self) -> &'static str {
        "Stack should contain only allowed user-defined resources"
    }

    fn should_run(&self, _stack: &Stack, _platform: Platform) -> bool {
        true // Always run this check
    }

    async fn check(&self, stack: &Stack, _platform: Platform) -> Result<CheckResult> {
        let allowed_types = HashSet::from([
            "function",
            "storage",
            "artifact-registry",
            "build",
            "queue",
            "kv",
            "vault",
            "container",
            "service-account",
        ]);

        let mut errors = Vec::new();

        for (resource_id, resource_entry) in stack.resources() {
            let resource_type_value = resource_entry.config.resource_type();
            let resource_type = resource_type_value.0.as_ref();

            if !allowed_types.contains(resource_type) {
                errors.push(format!(
                    "Resource '{}' has type '{}' which is not allowed. User-defined resources must be one of: {}",
                    resource_id,
                    resource_type,
                    allowed_types.iter().map(|s| format!("'{}'", s)).collect::<Vec<_>>().join(", ")
                ));
            }
        }

        if errors.is_empty() {
            Ok(CheckResult::success())
        } else {
            Ok(CheckResult::failed(errors))
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use alien_core::{Function, FunctionCode, ResourceEntry, ResourceLifecycle, Storage};
    use indexmap::IndexMap;

    #[tokio::test]
    async fn test_allowed_user_resources_success() {
        let storage = Storage::new("test-storage".to_string()).build();
        let function = Function::new("test-function".to_string())
            .code(FunctionCode::Image {
                image: "test:latest".to_string(),
            })
            .permissions("test".to_string())
            .build();

        let mut resources = IndexMap::new();
        resources.insert(
            "test-storage".to_string(),
            ResourceEntry {
                config: alien_core::Resource::new(storage),
                lifecycle: ResourceLifecycle::Frozen,
                dependencies: Vec::new(),
                remote_access: false,
            },
        );
        resources.insert(
            "test-function".to_string(),
            ResourceEntry {
                config: alien_core::Resource::new(function),
                lifecycle: ResourceLifecycle::Live,
                dependencies: Vec::new(),
                remote_access: false,
            },
        );

        let stack = Stack {
            id: "test-stack".to_string(),
            resources,
            permissions: alien_core::permissions::PermissionsConfig::default(),
            supported_platforms: None,
        };

        let check = AllowedUserResourcesCheck;
        let result = check.check(&stack, Platform::Aws).await.unwrap();
        assert!(result.success);
        assert!(result.errors.is_empty());
    }

    #[tokio::test]
    async fn test_allowed_user_resources_failure() {
        // Create a stack with an invalid resource type (Network is system-managed)
        let mut resources = IndexMap::new();

        let invalid_resource = alien_core::Resource::from_boxed(Box::new(
            alien_core::Network::new("my-network".to_string())
                .settings(alien_core::NetworkSettings::Create {
                    cidr: Some("10.0.0.0/16".to_string()),
                    availability_zones: 2,
                })
                .build(),
        ));

        resources.insert(
            "invalid-resource".to_string(),
            ResourceEntry {
                config: invalid_resource,
                lifecycle: ResourceLifecycle::Frozen,
                dependencies: Vec::new(),
                remote_access: false,
            },
        );

        let stack = Stack {
            id: "test-stack".to_string(),
            resources,
            permissions: alien_core::permissions::PermissionsConfig::default(),
            supported_platforms: None,
        };

        let check = AllowedUserResourcesCheck;
        let result = check.check(&stack, Platform::Aws).await.unwrap();
        assert!(!result.success);
        assert!(!result.errors.is_empty());
        assert!(result.errors[0].contains("network"));
    }
}
